import { MakeLogicType, actions, connect, kea, path } from 'kea'
import { loaders } from 'kea-loaders'

import { lemonToast } from '@posthog/lemon-ui'

import api from 'lib/api'
import { userLogic } from 'scenes/userLogic'
import type { UserType } from '../../../../frontend/src/types'


// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface optOutSceneLogicValues {
    user: UserType | null; // userLogic
    preferencesUrl: string | null;
    preferencesUrlLoading: boolean;
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface optOutSceneLogicActions {
    loadUnsubscribeLink: () => {
        value: true;
    };
    openPreferencesPage: (recipient?: string) => string;
    openPreferencesPageFailure: (error: string, errorObject?: any) => {
        error: string;
        errorObject?: any;
    };
    openPreferencesPageSuccess: (preferencesUrl: string | null, payload?: string) => {
        preferencesUrl: string | null;
        payload?: string;
    };
}

export type optOutSceneLogicType = MakeLogicType<optOutSceneLogicValues, optOutSceneLogicActions>;

export const optOutSceneLogic = kea<optOutSceneLogicType>([
    path(['products', 'workflows', 'frontend', 'OptOuts', 'optOutSceneLogic']),
    connect(() => ({
        values: [userLogic, ['user']],
    })),
    actions({
        loadUnsubscribeLink: true,
    }),
    loaders(({ values }) => ({
        preferencesUrl: {
            __default: null as string | null,
            openPreferencesPage: async (recipient?: string): Promise<string | null> => {
                if (!values.user?.email) {
                    lemonToast.error('User email not found')
                    return null
                }

                try {
                    const newPreferencesUrl = await api.messaging.generateMessagingPreferencesLink(
                        recipient ?? values.user.email
                    )
                    if (!newPreferencesUrl) {
                        lemonToast.error('Failed to generate workflows preferences link')
                        return null
                    }
                    window.open(newPreferencesUrl, '_blank')
                    return newPreferencesUrl
                } catch {
                    lemonToast.error('Failed to generate workflows preferences link')
                    return null
                }
            },
        },
    })),
])
